#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) {
    unsigned char poc[] = {0x00, 0x01, 0x02, 0x03}; 
    size_t poc_len = sizeof(poc);

    FILE *f = fopen("/tmp/poc", "wb");
    if (f == NULL) { 
        perror("Error opening file");
        return EXIT_FAILURE; 
    }
    if(fwrite(poc, 1, poc_len, f) != poc_len) {
        perror("Error writing to file");
        return EXIT_FAILURE;
    }
    if(fclose(f) != 0) {
        perror("Error closing file");
        return EXIT_FAILURE;
    }
    return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    unsigned char poc[] = {0x00};
    size_t poc_len = sizeof(poc);

    FILE *f = fopen("/tmp/poc", "wb");
    if (!f) { 
        printf("Error opening file\n");
        return 1; 
    }
    fwrite(poc, 1, poc_len, f);
    fclose(f);
    return 0;
}
